// src/pages/LeaveBalance.js
import React from 'react';
import { useApp } from '../context/AppContext';
import { LEAVE_BALANCES } from '../data/initialData';

export default function LeaveBalance() {
  const { currentUser, staff, leaveRequests } = useApp();
  const isAdmin = currentUser.role === 'admin';
  const staffToShow = isAdmin ? staff : staff.filter(t => t.id === currentUser.id);

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>📊 Leave Balance</h1>
        <p style={styles.subtitle}>
          {isAdmin ? 'All faculty leave balances' : 'Your remaining leave balance'}
        </p>
      </div>

      {staffToShow.map(teacher => {
        const myLeaves = leaveRequests.filter(
          r => r.teacherId === teacher.id && r.status === 'approved'
        );

        const usedDays = (type) => myLeaves
          .filter(r => r.reason?.toLowerCase().includes(type))
          .reduce((sum, r) => {
            const days = Math.ceil(
              (new Date(r.toDate) - new Date(r.fromDate)) / (1000 * 60 * 60 * 24)
            ) + 1;
            return sum + days;
          }, 0);

        return (
          <div key={teacher.id} style={styles.card}>
            <div style={styles.cardHeader}>
              <div style={styles.avatar}>{teacher.name[0]}</div>
              <div>
                <div style={styles.teacherName}>{teacher.name}</div>
                <div style={styles.dept}>{teacher.department} | {teacher.subject}</div>
              </div>
            </div>

            <div style={styles.balanceGrid}>
              {Object.entries(LEAVE_BALANCES).map(([type, info]) => {
                const used = usedDays(type);
                const isDuty = type === 'duty';
                const remaining = isDuty ? '∞' : Math.max(0, info.total - used);
                const percent = isDuty ? 100 : Math.round(((info.total - used) / info.total) * 100);
                const isLow = !isDuty && remaining <= 3;

                return (
                  <div key={type} style={{ ...styles.balanceCard, borderTop: `4px solid ${info.color}` }}>
                    <div style={styles.balanceIcon}>{info.icon}</div>
                    <div style={styles.balanceLabel}>{info.label}</div>
                    <div style={styles.balanceNumbers}>
                      <span style={{ ...styles.remaining, color: isLow ? '#ef4444' : info.color }}>
                        {remaining}
                      </span>
                      <span style={styles.total}>/ {isDuty ? '∞' : info.total}</span>
                    </div>
                    {!isDuty && (
                      <>
                        <div style={styles.progressBg}>
                          <div style={{
                            ...styles.progressFill,
                            width: `${percent}%`,
                            background: isLow ? '#ef4444' : info.color,
                          }} />
                        </div>
                        <div style={styles.usedText}>Used: {used} day(s)</div>
                        {isLow && <div style={styles.lowWarning}>⚠ Low balance!</div>}
                      </>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        );
      })}
    </div>
  );
}

const styles = {
  container: { padding: 32, maxWidth: 1100, margin: '0 auto' },
  header: { marginBottom: 28 },
  title: { fontSize: 28, fontWeight: 800, color: '#1e293b', margin: 0 },
  subtitle: { color: '#64748b', marginTop: 6 },
  card: {
    background: '#fff', borderRadius: 20, padding: 28,
    boxShadow: '0 2px 20px rgba(0,0,0,0.06)',
    border: '1px solid #f1f5f9', marginBottom: 24,
  },
  cardHeader: { display: 'flex', alignItems: 'center', gap: 16, marginBottom: 24 },
  avatar: {
    width: 52, height: 52, borderRadius: '50%',
    background: 'linear-gradient(135deg, #63b3ed, #9f7aea)',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    color: '#fff', fontWeight: 800, fontSize: 22, flexShrink: 0,
  },
  teacherName: { fontWeight: 800, fontSize: 17, color: '#1e293b' },
  dept: { color: '#64748b', fontSize: 13, marginTop: 2 },
  balanceGrid: { display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 16 },
  balanceCard: {
    background: '#f8fafc', borderRadius: 14, padding: 20,
    border: '1px solid #e2e8f0', textAlign: 'center',
  },
  balanceIcon: { fontSize: 28, marginBottom: 6 },
  balanceLabel: { fontSize: 13, fontWeight: 700, color: '#374151', marginBottom: 12 },
  balanceNumbers: { display: 'flex', alignItems: 'baseline', justifyContent: 'center', gap: 4, marginBottom: 10 },
  remaining: { fontSize: 36, fontWeight: 800, lineHeight: 1 },
  total: { fontSize: 16, color: '#94a3b8', fontWeight: 600 },
  progressBg: { height: 8, background: '#e2e8f0', borderRadius: 4, overflow: 'hidden', marginBottom: 8 },
  progressFill: { height: '100%', borderRadius: 4, transition: 'width 0.5s ease' },
  usedText: { fontSize: 11, color: '#94a3b8' },
  lowWarning: { fontSize: 11, color: '#ef4444', fontWeight: 700, marginTop: 4 },
};
